import difflibimport jsonimport osimport posixpathimport statimport tarfileimport paramikofrom core.llm_client import LintLLMClientclass PiDevBridge:    SNAPSHOT_EXTENSIONS = (".py", ".txt", ".json", ".md", ".env", ".bat", ".yml", ".yaml")    ARCHIVE_EXCLUDE_PATTERNS = (".git", "__pycache__", ".venv", ".idea")    MAX_PARSE_RETRIES = 2    def __init__(self, workspace_root: str, pi_host="lintbox.local", pi_user="pi"):        self.workspace_root = os.path.realpath(workspace_root)        self.host = pi_host        self.user = pi_user        self.password = os.getenv("PI_PASSWORD", "")        self.remote_dir = "/home/pi/sandbox/workspace"        self.max_loops = 3        self.llm = LintLLMClient()    def _create_ssh_client(self):        client = paramiko.SSHClient()        client.load_system_host_keys()        client.set_missing_host_key_policy(paramiko.RejectPolicy())        return client    def _build_project_snapshot(self):        snapshot = {}        base = self.workspace_root  # FIX: was self.sandbox_root        for root, _, files in os.walk(base):            if any(p in root for p in self.ARCHIVE_EXCLUDE_PATTERNS):                continue            for f in files:                if f.endswith(self.SNAPSHOT_EXTENSIONS) or f == "Dockerfile":                    full = os.path.join(root, f)                    rel = os.path.relpath(full, base)                    with open(full, "r", encoding="utf-8") as stream:                        snapshot[rel] = stream.read()        return snapshot    @staticmethod    def _should_archive_entry(tarinfo, archive_name):        if archive_name in tarinfo.name:            return None        if any(pattern in tarinfo.name for pattern in PiDevBridge.ARCHIVE_EXCLUDE_PATTERNS):            return None        return tarinfo    @staticmethod    def _normalize_llm_payload(raw_json_reply: str):        decoder = json.JSONDecoder()        payload = (raw_json_reply or "").strip()        try:            direct = json.loads(payload)            if isinstance(direct, dict):                parsed = direct            else:                parsed = None        except json.JSONDecodeError:            parsed = None        next_idx = payload.find("{")        while parsed is None and next_idx != -1:            try:                candidate, _ = decoder.raw_decode(payload[next_idx:])                if isinstance(candidate, dict):                    parsed = candidate                    break            except json.JSONDecodeError:                pass            next_idx = payload.find("{", next_idx + 1)        if parsed is None:            raise ValueError("unable to locate a parseable top-level JSON object in LLM payload")        if "mutations" in parsed:            mutations = parsed.get("mutations")            if not isinstance(mutations, dict):                mutations = {}            commands_run = parsed.get("commands_run")            if not isinstance(commands_run, list):                commands_run = []            return {                "summary": parsed.get("summary", ""),                "rationale": parsed.get("rationale", ""),                "commands_run": commands_run,                "mutations": mutations,                "done": bool(parsed.get("done", False)),            }        return {            "summary": "",            "rationale": "",            "commands_run": [],            "mutations": parsed,            "done": False,        }    def _resolve_safe_path(self, rel_path: str = "") -> str:        candidate = os.path.realpath(            os.path.join(self.workspace_root, rel_path)        )        root = self.workspace_root        if candidate != root and not candidate.startswith(root + os.sep):            raise ValueError(f"blocked path escape: {rel_path}")        return candidate    @staticmethod    def _build_unified_diff(rel_path: str, original_content: str, updated_content: str) -> str:        diff = difflib.unified_diff(            original_content.splitlines(keepends=True),            updated_content.splitlines(keepends=True),            fromfile=f"a/{rel_path}",            tofile=f"b/{rel_path}",        )        return "".join(diff)    @staticmethod    def _render_diff_report(task_instruction, loop_notes, commands_run, per_file_diff, parse_retry_events):        report_lines = [            "# Lint Sandbox Agent Report",            f"**Task**: {task_instruction}",            "",            "## Summary",        ]        if loop_notes:            report_lines.extend(f"- {note}" for note in loop_notes)        else:            report_lines.append("- No changes were required.")        report_lines.extend(["", "## Commands Executed on Raspberry Pi Sandbox"])        if commands_run:            report_lines.extend(f"- `{cmd}`" for cmd in commands_run)        else:            report_lines.append("- None")        report_lines.extend(["", "## JSON Parse Recovery"])        if parse_retry_events:            report_lines.extend(f"- {event}" for event in parse_retry_events)        else:            report_lines.append("- No parse retries were required.")        report_lines.extend(["", "## Unified Diffs"])        if per_file_diff:            for rel_path, diff_text in per_file_diff.items():                report_lines.append(f"### `{rel_path}`")                report_lines.append("```diff")                report_lines.append(diff_text.rstrip("\n"))                report_lines.append("```")                report_lines.append("")        else:            report_lines.append("_No file differences detected._")        return "\n".join(report_lines).strip() + "\n"    def _clear_sftp_directory(self, sftp, remote_path):        for entry in sftp.listdir_attr(remote_path):            child_path = posixpath.join(remote_path, entry.filename)            if stat.S_ISDIR(entry.st_mode):                self._clear_sftp_directory(sftp, child_path)                sftp.rmdir(child_path)            else:                sftp.remove(child_path)    def _fetch_remote_snapshot(self, sftp, remote_path: str, base_name: str) -> dict:        """Fetch all modified files from remote sandbox."""        remote_snapshot = {}        def walk_remote(current_path):            try:                for entry in sftp.listdir_attr(current_path):                    entry_path = posixpath.join(current_path, entry.filename)                    rel_from_base = posixpath.relpath(entry_path, f"{self.remote_dir}/{base_name}")                    if stat.S_ISDIR(entry.st_mode):                        if not any(p in entry.filename for p in self.ARCHIVE_EXCLUDE_PATTERNS):                            walk_remote(entry_path)                    elif entry.filename.endswith(self.SNAPSHOT_EXTENSIONS) or entry.filename == "Dockerfile":                        try:                            with sftp.open(entry_path, "r") as f:                                content = f.read().decode("utf-8", errors="ignore")                                remote_snapshot[rel_from_base] = content                        except Exception:                            pass            except Exception:                pass        walk_remote(remote_path)        return remote_snapshot    def _validate_shell_command(self, cmd: str):        blocked = [            "cd ..",            "../",            "~",            "sudo",            "shutdown",            "reboot",        ]        lowered = cmd.lower()        for token in blocked:            if token in lowered:                raise ValueError(f"blocked shell token: {token}")    def _is_safe_relative_path(self, rel_path: str, base_dir: str) -> bool:        """        Safely check if rel_path is within base_dir.        Works correctly on both POSIX and Windows.        """        # Reject obviously dangerous patterns        if rel_path.startswith("~") or os.path.isabs(rel_path):            return False        if ".." in rel_path:            return False        # Normalize and resolve        target = os.path.normpath(os.path.join(base_dir, rel_path))        base_normalized = os.path.normpath(base_dir)        # Use os.path.commonpath to check if target is within base        try:            common = os.path.commonpath([base_normalized, target])            return common == base_normalized        except ValueError:            # Different drives on Windows            return False    def run_agentic_sandbox(self, task_instruction: str, run_cmd: str = "pwd") -> str:        if not self.password:            return "*yawns* add your PI_PASSWORD to your .env file, dummy."        # STRICT PATH LOCKING: Agent only knows about target_dir and lower.        abs_local_path = self.workspace_root        base_name = os.path.basename(abs_local_path)        archive_name = f"{base_name}_sandbox.tar.gz"        local_archive_path = os.path.join(abs_local_path, archive_name)        execution_path = f"{self.remote_dir}/{base_name}"        command_history = [run_cmd]        narrative_notes = []        parse_retry_events = []        print(f"\n[!] ALERT: Syncing strictly isolated directory '{base_name}' to Pi sandbox...")        try:            with tarfile.open(local_archive_path, "w:gz") as tar:                tar.add(                    abs_local_path,                    arcname=base_name,                    filter=lambda tarinfo: self._should_archive_entry(tarinfo, archive_name),                )            ssh = self._create_ssh_client()            ssh.connect(self.host, username=self.user, password=self.password, timeout=10)            sftp = ssh.open_sftp()            sftp.put(local_archive_path, f"{self.remote_dir}/{archive_name}")            if os.path.exists(local_archive_path):                os.remove(local_archive_path)            self._validate_shell_command(run_cmd)            ssh.exec_command(f"cd {self.remote_dir} && tar -xzf {archive_name} && rm {archive_name}")            print("[!] launching iterative verification agent loop on raspberry pi...")            remote_mutations_log = {}            baseline_snapshot = self._build_project_snapshot()            terminated_early = False            for current_iteration in range(1, self.max_loops + 1):                print(f"    -> [loop {current_iteration}/{self.max_loops}] running main verification command...")                _, stdout, stderr = ssh.exec_command(f"cd {execution_path} && {run_cmd}")                out_logs = stdout.read().decode("utf-8", errors="ignore").strip()                err_logs = stderr.read().decode("utf-8", errors="ignore").strip()                exit_status = stdout.channel.recv_exit_status()                combined_logs = f"STDOUT:\n{out_logs}\n\nSTDERR:\n{err_logs}".strip()                agent_prompt = (                    "Role: Autonomous Linux terminal operator and coding agent.\n"                    "Environment grounding (CRITICAL):\n"                    "- OS: Debian Linux (Raspberry Pi OS Lite 32-bit).\n"                    "- Shell: bash.\n"                    f"- Current Working Directory: /home/pi/sandbox/workspace/{base_name}\n"                    "- SCOPE LOCK: You are physically trapped in this directory. You cannot see, access, or modify parent directories.\n\n"                    "Capabilities & Rules:\n"                    "1. LINUX TERMINAL FIRST: To manage files (create, move, read), you MUST use standard Linux shell commands (mkdir, touch, echo, cat, rm) inside the `commands_run` array. The system WILL execute them.\n"                    "2. NO PYTHON HACKS: DO NOT write or modify Python scripts just to execute shell tasks (e.g., do not use open() in Python to create a text file). Use the terminal.\n"                    "3. SOURCE CODE: Only use `mutations` for legitimately editing existing application source code.\n\n"                    "Task objective:\n"                    f"{task_instruction}\n\n"                    f"Current test command: {run_cmd}\n"                    f"Test exit status: {'failed' if exit_status != 0 else 'passed'}\n"                    "Test console logs:\n"                    f"{combined_logs}\n\n"                    "Return ONLY ONE strict JSON object and no markdown/code fences.\n"                    "JSON schema:\n"                    "{\n"                    '  "summary": "what changed in plain language",\n'                    '  "rationale": "why those changes were needed",\n'                    '  "commands_run": ["linux bash command 1", "linux bash command 2"],\n'                    '  "mutations": {"relative/path.py": "full updated file content"},\n'                    '  "done": false\n'                    "}\n"                )                ctx_string = json.dumps(baseline_snapshot)                raw_json_reply = self.llm.ask_cat(agent_prompt, context=ctx_string, model_override="gemini-2.5-flash")                payload = None                last_parse_error = None                total_parse_attempts = self.MAX_PARSE_RETRIES + 1                for parse_attempt in range(1, total_parse_attempts + 1):                    try:                        payload = self._normalize_llm_payload(raw_json_reply)                        break                    except Exception as parse_error:                        last_parse_error = str(parse_error)                        if parse_attempt == total_parse_attempts:                            parse_retry_events.append(f"loop {current_iteration}: parse failed ({last_parse_error}).")                            narrative_notes.append("LLM payload could not be parsed; loop terminated.")                            break                        parse_retry_events.append(f"loop {current_iteration}: parse retry {parse_attempt} triggered.")                        repair_prompt = (                            "Your previous response was not parseable JSON. Return ONLY one valid JSON object with the exact schema. No markdown fences.\n"                            f"Task objective: {task_instruction}\nPrevious invalid response:\n{raw_json_reply}"                        )                        raw_json_reply = self.llm.ask_cat(repair_prompt, context=ctx_string,                                                          model_override="gemini-2.0-flash")                if payload is None:                    terminated_early = True                    break                mutations = payload.get("mutations") or {}                done_signal = bool(payload.get("done", False))                if payload.get("summary"): narrative_notes.append(payload["summary"])                if payload.get("rationale"): narrative_notes.append(f"Rationale: {payload['rationale']}")                # ACTUALLY EXECUTE REQUESTED SHELL COMMANDS ON THE PI                for cmd in payload.get("commands_run") or []:                    if cmd not in command_history:                        command_history.append(cmd)                        print(f"    [agent shell] executing command: {cmd}")                        self._validate_shell_command(cmd)                        ssh.exec_command(f"cd {execution_path} && {cmd}")                # APPLY FILE MUTATIONS                for rel_path, new_content in mutations.items():                    # FIX: Use centralized safe path check                    if not self._is_safe_relative_path(rel_path, execution_path):                        print(f"    [!] Security: Blocked dangerous path -> {rel_path}")                        continue                    remote_file_target = posixpath.join(execution_path, rel_path)                    print(f"    [mutation] rewriting file: {rel_path}")                    remote_mutations_log[rel_path] = new_content                    remote_parent = posixpath.dirname(remote_file_target)                    if remote_parent:                        ssh.exec_command(f"mkdir -p {remote_parent}")                    with sftp.open(remote_file_target, "w") as remote_file:                        remote_file.write(new_content)                if done_signal or (not mutations and not payload.get("commands_run")):                    narrative_notes.append("Agent signaled completion or had no further actions.")                    terminated_early = True                    break            if not terminated_early and self.max_loops > 0:                narrative_notes.append(f"Reached max loop count ({self.max_loops}).")            # FIX: Fetch remote snapshot to capture shell-created files            print("[!] Fetching final remote snapshot to capture all changes...")            final_remote_snapshot = self._fetch_remote_snapshot(sftp, execution_path, base_name)            per_file_diff = {}            all_mutations_log = {}            # Helper to strip out line-ending mismatches            def _norm(text: str) -> str:                return (text or "").replace('\r\n', '\n').replace('\r', '\n')            # Include explicitly mutated files            for rel_path, new_content in remote_mutations_log.items():                original = _norm(baseline_snapshot.get(rel_path, ""))                norm_new = _norm(new_content)                diff_text = self._build_unified_diff(rel_path, original, norm_new)                if diff_text:                    per_file_diff[rel_path] = diff_text                all_mutations_log[rel_path] = norm_new            # Include shell-created/modified files            for rel_path, remote_content in final_remote_snapshot.items():                if rel_path not in remote_mutations_log:  # Don't double-count explicit mutations                    original = _norm(baseline_snapshot.get(rel_path, ""))                    norm_remote = _norm(remote_content)                    if norm_remote != original:                        diff_text = self._build_unified_diff(rel_path, original, norm_remote)                        if diff_text:                            per_file_diff[rel_path] = diff_text                        all_mutations_log[rel_path] = norm_remote            diff_markdown_content = self._render_diff_report(                task_instruction, narrative_notes, command_history, per_file_diff, parse_retry_events            )            diff_path = self._resolve_safe_path("diff.md")            with open(diff_path, "w", encoding="utf-8") as diff_file:                diff_file.write(diff_markdown_content)            # FIX: Store complete mutations log (including shell-created files)            mutations_json_path = self._resolve_safe_path(".sandbox_mutations.json")            with open(mutations_json_path, "w", encoding="utf-8") as mutations_file:                json.dump(all_mutations_log, mutations_file, indent=2)            self.llm.memory.add_entry("sandbox", task_instruction, "; ".join(narrative_notes[:4]))            sftp.close()            ssh.close()            return "*purrs* sandbox run complete. review runtime diff.md. type 'sandbox accept' to apply locally."        except Exception as e:            if os.path.exists(local_archive_path): os.remove(local_archive_path)            return f"*hisses* agent loop failed: {str(e)}"    def sandbox_accept(self) -> str:        """Apply changes from local .sandbox_mutations.json to working directory."""        abs_local_path = self.workspace_root        mutations_json_path = os.path.join(abs_local_path, ".sandbox_mutations.json")        if not os.path.exists(mutations_json_path):            return "*stares* no .sandbox_mutations.json found. run sandbox first."        try:            with open(mutations_json_path, "r", encoding="utf-8") as f:                mutations = json.load(f)            if not mutations:                return "*yawns* mutations file was empty."            applied_count = 0            rejected_count = 0            for rel_path, content in mutations.items():                # FIX: Use centralized safe path check                if not self._is_safe_relative_path(rel_path, abs_local_path):                    print(f"[!] sandbox accept blocked dangerous path: {rel_path}")                    rejected_count += 1                    continue                local_file_target = self._resolve_safe_path(rel_path)                os.makedirs(os.path.dirname(local_file_target), exist_ok=True)                with open(local_file_target, "w", encoding="utf-8") as f:                    f.write(content)                print(f"[accepted] {rel_path}")                applied_count += 1            # Clean up after accept            os.remove(mutations_json_path)            if rejected_count:                return f"*purrs* applied {applied_count} changes; rejected {rejected_count} unsafe path(s)."            return f"*purrs unthrottled* sandbox accepted and applied {applied_count} file change(s) to your workspace."        except Exception as e:            return f"*hisses* sandbox accept failed: {str(e)}"    def pull_remote_mutations(self) -> str:        return self.sandbox_accept()    def clear_remote_sandbox(self, confirmation: str) -> str:        expected = "confirm clear sandbox"        if confirmation.strip().lower() != expected:            return f"*stares* cleanup blocked. run: sandbox clear {expected}"        if not self.password:            return "*yawns* configure your password environment."        normalized_target = posixpath.normpath(self.remote_dir)        if normalized_target != "/home/pi/sandbox/workspace":            return "*hisses* cleanup blocked because sandbox path safety check failed."        try:            ssh = self._create_ssh_client()            ssh.connect(self.host, username=self.user, password=self.password, timeout=10)            sftp = ssh.open_sftp()            try:                sftp.stat(normalized_target)            except FileNotFoundError:                sftp.close()                ssh.close()                return "*hisses* sandbox cleanup failed because workspace path was missing."            self._clear_sftp_directory(sftp, normalized_target)            sftp.close()            ssh.close()            return "*purrs* sandbox workspace contents cleared safely."        except Exception as e:            return f"*hisses* sandbox cleanup failed: {str(e)}"